<?php

declare(strict_types=1);

namespace DrevOps\EnvironmentDetector\Platforms;

use DrevOps\EnvironmentDetector\Contexts\Drupal;
use DrevOps\EnvironmentDetector\Contexts\DrupalContextualizerInterface;
use DrevOps\EnvironmentDetector\Environment;

/**
 * Lagoon hosting platform.
 *
 * @package DrevOps\EnvironmentDetector\Platforms
 */
class Lagoon extends AbstractPlatform implements DrupalContextualizerInterface {

  /**
   * {@inheritdoc}
   */
  public const ID = 'lagoon';

  /**
   * {@inheritdoc}
   */
  public function active(): bool {
    return getenv('LAGOON_KUBERNETES') !== FALSE;
  }

  /**
   * {@inheritdoc}
   */
  public function type(): ?string {
    $env_type = getenv('LAGOON_ENVIRONMENT_TYPE');

    if ($env_type === 'production') {
      return Environment::PRODUCTION;
    }

    // Anything Lagoon does not type as 'production' or 'development' is not one
    // of the persistent tiers, so it is an ephemeral preview. A 'development'
    // environment is narrowed to a tier by its deployed branch below.
    if ($env_type !== 'development') {
      return Environment::PREVIEW;
    }

    $branch = (string) getenv('LAGOON_GIT_BRANCH');

    // `ENVIRONMENT_PRODUCTION_BRANCH` is a custom project variable naming the
    // branch deployed as production when Lagoon has not marked the environment
    // as 'production' itself.
    if ($branch !== '' && $branch === getenv('ENVIRONMENT_PRODUCTION_BRANCH')) {
      return Environment::PRODUCTION;
    }

    // `main`/`master` is a stage when production runs on another branch.
    if ($branch === 'main' || $branch === 'master') {
      return Environment::STAGE;
    }

    // Release and hotfix branches are cut for pre-production sign-off.
    if (str_starts_with($branch, 'release/') || str_starts_with($branch, 'hotfix/')) {
      return Environment::STAGE;
    }

    if ($branch === static::DEVELOPMENT_BRANCH) {
      return Environment::DEVELOPMENT;
    }

    // Any other branch is an ephemeral per-branch build - a preview.
    return Environment::PREVIEW;
  }

  /**
   * {@inheritdoc}
   */
  public function contextualizeDrupal(Drupal $context): void {
    $settings = &$context->settings;

    // Lagoon reverse proxy settings.
    $settings['reverse_proxy'] = TRUE;
    $settings['reverse_proxy_header'] = 'HTTP_TRUE_CLIENT_IP';

    // Cache prefix.
    if (getenv('LAGOON_PROJECT') && (getenv('LAGOON_GIT_SAFE_BRANCH') || getenv('ENVIRONMENT_PRODUCTION_BRANCH'))) {
      $settings['cache_prefix'] = getenv('LAGOON_PROJECT') . '_' . (getenv('LAGOON_GIT_SAFE_BRANCH') ?: getenv('ENVIRONMENT_PRODUCTION_BRANCH'));
    }

    // URL when accessed from PHP processes in Lagoon.
    $settings['trusted_host_patterns'][] = '^nginx\-php$';

    // Trust amazee.io autogenerated internal routes (*.amazee.io).
    $settings['trusted_host_patterns'][] = '^.+\.amazee\.io$';

    // Turn the comma-separated LAGOON_ROUTES URL list into one anchored
    // trusted-host regex: escape dots, drop the scheme, and let the commas
    // become regex alternation.
    $routes = getenv('LAGOON_ROUTES');
    if (!empty($routes) && is_string($routes)) {
      $patterns = str_replace(['.', 'https://', 'http://', ','], [
        '\.', '', '', '|',
      ], $routes);
      $settings['trusted_host_patterns'][] = '^(' . $patterns . ')$';
    }
  }

}
